import{_ as i,o as s,c as t,a0 as r}from"./chunks/framework.jwovEGr5.js";const o="/assets/architecture.CQTXASkY.svg",g=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture.md","filePath":"guide/architecture.md"}'),a={name:"guide/architecture.md"};function n(l,e,c,d,u,p){return s(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><p>SwiftList employs a multi-process separated architecture consisting of <strong>&quot;System Service for Indexing + Hook Process for Input Interception + Application for UI Presentation&quot;</strong>.</p><h2 id="process-responsibilities" tabindex="-1">Process Responsibilities <a class="header-anchor" href="#process-responsibilities" aria-label="Permalink to &quot;Process Responsibilities&quot;">​</a></h2><p><img src="'+o+'" alt="Process Responsibilities"></p><h3 id="swiftlist-service-indexer-mode-system-privilege" tabindex="-1">SwiftList.Service (Indexer Mode - SYSTEM Privilege) <a class="header-anchor" href="#swiftlist-service-indexer-mode-system-privilege" aria-label="Permalink to &quot;SwiftList.Service (Indexer Mode - SYSTEM Privilege)&quot;">​</a></h3><ul><li><strong>Responsibilities</strong>: High-performance background indexer daemon.</li><li>Scans local NTFS drive MFT and monitors USN Journal.</li><li>Keeps the <code>RuntimeIndex</code> resident in memory for lightning-fast matching.</li><li>Hosts the Named Pipe server (<code>&quot;SwiftListPipe&quot;</code>).</li><li><strong>System-Wide Shared</strong>: DB and memory structures are system-wide unique.</li></ul><h3 id="swiftlist-service-hook-mode-user-privilege" tabindex="-1">SwiftList.Service (Hook Mode - User Privilege) <a class="header-anchor" href="#swiftlist-service-hook-mode-user-privilege" aria-label="Permalink to &quot;SwiftList.Service (Hook Mode - User Privilege)&quot;">​</a></h3><ul><li><strong>Responsibilities</strong>: System-wide input hook and window focus tracker (runs via <code>Service.exe --hook</code>).</li><li>Registers and intercepts Windows global keyboard hotkeys to trigger quick activation.</li><li>Monitors explorer windows and active terminals via Win32 hooks to track physical paths in real time.</li><li>Hosts a session-local Named Pipe server to communicate hook inputs back to the App.</li><li><strong>Session Bound</strong>: Starts and executes independently inside each logged-in user&#39;s desktop session.</li></ul><h3 id="swiftlist-app-user-privilege" tabindex="-1">SwiftList.App (User Privilege) <a class="header-anchor" href="#swiftlist-app-user-privilege" aria-label="Permalink to &quot;SwiftList.App (User Privilege)&quot;">​</a></h3><ul><li>Provides a lightweight WPF query window, handling user input and search result rendering.</li><li>Sends <code>SearchRequestMessage</code> to the Service, and retrieves user-customized search results isolated by <code>AsyncLocal</code>.</li><li>Loads user-specific plugins such as custom alias extensions.</li></ul>',10)])])}const m=i(a,[["render",n]]);export{g as __pageData,m as default};
